"""
MKT Christ Commentary — Jeremiah 46–48 (fill script)
Run: python3 scripts/zc-christ-jeremiah-46-48-fill.py

Ch 46: Oracle Against Egypt — Egypt as the antithesis of salvation-history; the "Fear not, Jacob"
       oracle (46:27-28) is the gospel heart of the chapter: YHWH's covenant faithfulness to his
       people amid the ruin of nations.
Ch 47: Oracle Against Philistia — the sword that cannot rest; divine purposes that cannot be stopped.
Ch 48: Oracle Against Moab — the longest OAN, with the surprise restoration promise (48:47);
       Ruth the Moabite in Jesus's genealogy (Matt 1:5) makes Moab's inclusion in the latter days
       a christological reality.

Key Christological nodes:
- 46:11 "no healing for you" → Christ as Great Physician; Isa 53:5
- 46:22 "hissing serpent" → Gen 3:15; the serpent Christ crushes
- 46:27-28 "do not fear, O Jacob my servant" → Isa 41:10; Christ's "do not be afraid"
- 47:6-7 "O sword of the LORD, how long?" → Rev 6:10; John 19:11
- 48:11 "settled on his dregs, never poured from vessel to vessel" → John 15:2; purification through suffering
- 48:17 "powerful scepter broken" → Ps 2:9; Christ's unbreakable scepter
- 48:42 "destroyed because he lifted himself up against the LORD" → Phil 2:9-11
- 48:47 "in the latter days I will restore the fortunes of Moab" → Ruth 1-4; Matt 1:5; the nations in Christ
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JEREMIAH = {
"46": {
"1": "<p>The heading: &quot;the word of the LORD that came to Jeremiah concerning the nations.&quot; The Oracles Against the Nations (chapters 46-51) frame YHWH as the sovereign judge of all history, not merely Israel&apos;s tribal deity. John 5:22 — &quot;the Father judges no one, but has entrusted all judgment to the Son.&quot; Acts 17:31 — &quot;he has set a day when he will judge the world with justice by the man he has appointed.&quot; The Oracles Against the Nations in Jeremiah are the prophetic pre-enactment of the universal judgment that Christ will execute at his return.</p>",
"2": "<p>Carchemish (605 BC) — the battle that ended Egyptian dominance and established Babylonian hegemony over the Near East. It is also the year of Daniel&apos;s first deportation (Dan 1:1). The convergence places the Oracles Against Egypt at the exact historical hinge that sets in motion the seventy-year exile from which Jeremiah&apos;s prophecies of restoration will emerge — and from which Daniel&apos;s seventy-weeks calculation (Dan 9:24-27) stretches forward to Christ. Egypt&apos;s defeat at Carchemish is the first domino in the chronological chain leading to the incarnation.</p>",
"3": "<p>&quot;Prepare the small shield and the large shield, and advance for battle.&quot; The ironic military call — the call is addressed to Egypt, which will be defeated. The armor prepared for earthly battle is contrasted with the spiritual armor Paul describes in Ephesians 6:11-17: &quot;put on the full armor of God, so that you can take your stand against the devil&apos;s schemes.&quot; Egypt&apos;s physical shields are useless against divine judgment; Christ&apos;s armor (truth, righteousness, the gospel of peace, faith, salvation, the word of God) is the equipment that actually wins.</p>",
"4": "<p>&quot;Harness the horses; mount, O horsemen! Fall in with your helmets!&quot; The marshaling of military power. Psalm 20:7 — &quot;some trust in chariots and some in horses, but we trust in the name of the LORD our God.&quot; Revelation 19:11 depicts Christ himself as the rider on a white horse, but he rides to execute judgment, not to be defeated. Egypt&apos;s chariot-and-horseman confidence is the false trust that Christ displaces; his coming on horseback is not Egypt&apos;s failure repeated but the final victory that Pharaoh&apos;s chariots could never achieve.</p>",
"5": "<p>&quot;Why do I see them dismayed and retreating?&quot; The sudden collapse of military confidence — the warriors who fled headlong. Isaiah 31:3 — &quot;the Egyptians are human and not God; their horses are flesh and not spirit.&quot; The fragility of flesh-confidence is the recurring OT lesson that Christ fulfills: 2 Corinthians 12:9 — &quot;my power is made perfect in weakness.&quot; The terrified warriors of Jer 46:5 who flee are the antithesis of Christ before Pilate — the one who could have called twelve legions of angels but chose not to (Matt 26:53).</p>",
"6": "<p>&quot;The swift cannot flee, nor can the mighty man escape; to the north, by the Euphrates, they stumble and fall.&quot; The inescapability of divine judgment — no speed or strength avoids it. Romans 2:3 — &quot;do you think you will escape God&apos;s judgment?&quot; The Euphrates as the site of Egypt&apos;s stumbling is the site of Babylon&apos;s dominance — and in Revelation, the Euphrates is dried up for the final battle (Rev 16:12). The river that witnessed Egypt&apos;s fall witnesses the fall of all empires before Christ&apos;s ultimate victory.</p>",
"7": "<p>&quot;Who is this, rising like the Nile?&quot; The rhetorical question about Egypt&apos;s threatening rise. The ironic answer is that Egypt&apos;s confident flooding is about to recede. Daniel 7:3 uses the same sea/flood imagery for the four empires that rise before the coming of the Son of Man. Christ&apos;s coming is not a rising like the Nile (impressive then gone) but a kingdom that fills the whole earth (Dan 2:35 — the stone becomes a great mountain) and never recedes.</p>",
"8": "<p>&quot;Egypt rises like the Nile... It said: I will rise, I will cover the earth; I will destroy the city and its inhabitants.&quot; Imperial self-declaration — the voice of Babylon/Egypt/Rome across history: &quot;I will cover the earth.&quot; Isaiah 14:13-14 (the king of Babylon&apos;s &quot;I will&quot; speeches) and Revelation 13:4 (&quot;who is like the beast? Who can wage war against it?&quot;) are the same voice. Christ answers all imperial &quot;I will cover the earth&quot; declarations with his own: Matthew 28:18 — &quot;all authority in heaven and on earth has been given to me&quot; — and Revelation 11:15 — &quot;the kingdom of the world has become the kingdom of our Lord and of his Messiah.&quot;</p>",
"9": "<p>The advance of Ethiopia, Put, and Lydia alongside Egypt — the international coalition of Egypt&apos;s army. The multi-national coalition assembled against YHWH&apos;s purposes is the recurring pattern of Revelation&apos;s Armageddon-battle (Rev 16:14 — &quot;the kings of the whole world, to gather them for the battle on the great day of God Almighty&quot;). Every historical coalition against God&apos;s purposes prefigures and climaxes in the final gathering that Christ&apos;s return defeats.</p>",
"10": "<p>&quot;For that day belongs to the Lord GOD of hosts — a day of vengeance... the sword devours and is satisfied and drinks its fill of their blood.&quot; The Day of the LORD oracle. Revelation 19:15 — &quot;he treads the winepress of the fury of the wrath of God Almighty&quot; and 19:21 — &quot;the rest were killed with the sword coming out of the mouth of the rider on the horse.&quot; Christ is both the Lamb who was slain and the rider whose sword executes the final judgment. The Day of Vengeance of Jer 46:10 finds its fullest form in Christ&apos;s parousia described in Rev 19.</p>",
"11": "<p><strong>&quot;Go up to Gilead and get balm, O virgin daughter of Egypt! You pile up medicine upon medicine in vain; there is no healing for you.&quot;</strong> The Gilead balm that cannot cure — the wound beyond natural medicine. Isaiah 53:5 — &quot;by his wounds we are healed.&quot; Matthew 9:12 — &quot;it is not the healthy who need a doctor, but the sick.&quot; The &quot;no healing for you&quot; verdict on Egypt is what applies to all humanity apart from Christ — the wound of sin has no natural remedy. He is the balm of Gilead in person: his death provides the healing that all human medicine piles up in vain to achieve. Jeremiah&apos;s lament over Judah (8:22 — &quot;is there no balm in Gilead?&quot;) is answered by the one whose stripes bring healing.</p>",
"12": "<p>&quot;The nations have heard your shame, and the earth is filled with your cry.&quot; Egypt&apos;s shame broadcast to the nations. Hebrews 12:2 — Jesus &quot;for the joy set before him endured the cross, scorning its shame.&quot; The difference between Egypt&apos;s shame and Christ&apos;s is the direction: Egypt is shamed by defeat; Christ voluntarily takes shame to achieve victory. The &quot;earth filled with your cry&quot; of Egypt&apos;s defeat becomes at the cross the cry of the Son who bore the world&apos;s shame — Matthew 27:50 — &quot;Jesus cried out again in a loud voice and gave up his spirit.&quot;</p>",
"13": "<p>The second Egypt oracle — concerning Nebuchadnezzar&apos;s advance to strike Egypt. The two oracles about Egypt (Carchemish, 46:2-12; and Nebuchadnezzar&apos;s invasion, 46:13-26) frame God&apos;s sustained purposes across decades. Hebrews 1:1 — &quot;in the past God spoke to our ancestors through the prophets at many times and in various ways.&quot; The successive divine announcements across years mirror the &quot;many times and various ways&quot; that climax in the Son&apos;s definitive word. What Egypt heard in two stages, the whole world hears in Christ&apos;s single comprehensive proclamation.</p>",
"14": "<p>&quot;Announce it in Egypt, proclaim it in Migdol... Take your positions and be ready, for the sword devours all around you.&quot; The call to ready attention — the watchman-announcement pattern. Matthew 24:42-44 — &quot;keep watch, because you do not know on what day your Lord will come... be ready, because the Son of Man will come at an hour when you do not expect him.&quot; The call to take positions and be ready in Jer 46:14 is the prophetic prototype of Christ&apos;s repeated call to watchfulness and readiness for his return.</p>",
"15": "<p>&quot;Why have your warriors been swept away? They could not stand, because the LORD thrust them down.&quot; The divine agency behind military defeat — YHWH himself thrusts down the warriors. 1 Corinthians 1:27-28 — &quot;God chose the weak things of the world to shame the strong... the things that are not — to nullify the things that are.&quot; Egypt&apos;s elite warriors cannot stand because YHWH nullifies them — the same logic by which the cross nullifies worldly power and wisdom. The &quot;swept away&quot; warriors anticipate the &quot;powers and authorities&quot; that Christ disarmed and made a public spectacle (Col 2:15).</p>",
"16": "<p>&quot;He made many stumble; they fell one upon another and said: Let us go back to our own people and to our native land.&quot; The rout that produces homeward flight. Luke 15:17-18 — the prodigal &quot;came to his senses&quot; and said: &quot;I will set out and go back to my father.&quot; The flight of the defeated soldiers home to their native land is structurally the same as the prodigal&apos;s return — but the soldiers flee from judgment while the prodigal returns to grace. Christ reframes all homeward impulses as a return to the Father.</p>",
"17": "<p>&quot;Pharaoh king of Egypt is nothing but noise — he has let the appointed time slip by.&quot; The king who missed his <em>môʿēd</em> — his appointed time. Galatians 4:4 — &quot;when the set time had fully come, God sent his Son.&quot; Romans 5:6 — &quot;at just the right time (<em>kata kairon</em>), when we were still powerless, Christ died for the ungodly.&quot; Pharaoh&apos;s failure is defined by missing the <em>môʿēd</em>; Christ&apos;s achievement is defined by arriving at the exact appointed time — the one who comes neither early nor late but at the fullness of time.</p>",
"18": "<p>&quot;As I live, declares the King — the LORD of hosts is his name — like Tabor towering over the mountains.&quot; The divine oath by YHWH&apos;s own life — the irrevocable guarantee. Hebrews 6:13-17 — &quot;when God made his promise to Abraham, since there was no one greater for him to swear by, he swore by himself... God wanted to make the unchanging nature of his purpose very clear.&quot; The divine self-oath of Jer 46:18 is the structure of the oath that guarantees Christ&apos;s high-priestly ministry (Heb 7:20-21 — &quot;the Lord has sworn and will not change his mind&quot;).</p>",
"19": "<p>&quot;Pack your bags for exile, O inhabitants of Egypt! For Memphis will become a desolation, a ruin without inhabitant.&quot; The great city emptied — the reversal of imperial permanence. Revelation 18:2 — &quot;Fallen! Fallen is Babylon the Great! She has become a dwelling for demons.&quot; All the great cities of human empire are ultimately emptied in Revelation&apos;s vision. Christ offers citizenship in the only city that lasts: Hebrews 11:10 — Abraham &quot;was looking forward to the city with foundations, whose architect and builder is God.&quot; Revelation 21:2 — the new Jerusalem coming down out of heaven from God.</p>",
"20": "<p>&quot;Egypt is a beautiful heifer, but a horsefly from the north has come against her.&quot; The beautiful-but-vulnerable imagery — power that appears impressive but is punctured by a small thing. 1 Corinthians 1:27-28 — &quot;God chose the foolish things of the world to shame the wise; God chose the weak things of the world to shame the strong.&quot; A horsefly defeating a heifer is the inverted logic of the gospel: the weakness of Christ crucified undoes the powers that appeared invincible. The heifer-and-horsefly dynamic is the OAN version of the stone cut without hands that shatters the great statue (Dan 2:34).</p>",
"21": "<p>&quot;Her hired soldiers in her midst are like fattened calves — they turned and fled together. They did not stand.&quot; The mercenary troops who abandon their post. John 10:12-13 — &quot;the hired hand is not the shepherd and does not own the sheep. So when he sees the wolf coming, he abandons the sheep and runs away.&quot; Christ is the Good Shepherd who, unlike Egypt&apos;s hired soldiers, does not flee when the danger comes: John 10:11 — &quot;the good shepherd lays down his life for the sheep.&quot; The hired-hand failure of Jer 46:21 is exactly what Christ refuses to do.</p>",
"22": "<p><strong>&quot;Her sound shall be like a hissing serpent, as they advance and come against her.&quot;</strong> Egypt hissing like a serpent in retreat. Genesis 3:14-15 — the serpent&apos;s curse: &quot;you will crawl on your belly and eat dust.&quot; God said to the serpent: &quot;I will put enmity between you and the woman, and between your offspring and hers; he will crush your head, and you will strike his heel.&quot; The serpent-hiss of defeated Egypt in Jer 46:22 connects to the serpent imagery that runs through scripture to its final defeat: Revelation 12:9 — &quot;the great dragon was hurled down — that ancient serpent called the devil.&quot; Christ crushes the serpent&apos;s head at the cross (Col 2:15; Heb 2:14).</p>",
"23": "<p>&quot;They shall cut down her forest, though it is dense; for they are more in number than locusts and are countless.&quot; The overwhelming force of Babylon. Revelation 9:3-6 describes the locust-plague from the abyss in the same overwhelming-number terms. The locusts of Jer 46:23 prefigure both the historical judgment-instruments and the end-time powers. But Revelation&apos;s locusts are ultimately defeated; Christ holds the keys of death and Hades (Rev 1:18) and stands above all the powers the forest-cutting armies represent.</p>",
"24": "<p>&quot;The daughter of Egypt is put to shame; she is handed over to a people from the north.&quot; The great handing-over — Egypt&apos;s control surrendered. Galatians 3:13 — &quot;Christ redeemed us from the curse of the law by becoming a curse for us.&quot; He himself was &quot;handed over&quot; to his enemies (John 19:16 — Pilate &quot;handed him over to them to be crucified&quot;) — the handing-over that destroys Egypt in Jer 46:24 becomes, in Christ, the voluntary surrender that achieves redemption. Egypt is shamed by being handed over; Christ transforms being handed over into the act of salvation.</p>",
"25": "<p>&quot;I am going to punish Amon of No, and Pharaoh, and Egypt with her gods and her kings.&quot; The judgment encompasses both political power and religious power — the gods fall alongside the kings. 1 Corinthians 8:5-6 — &quot;even if there are so-called gods, whether in heaven or on earth... yet for us there is but one God, the Father... and there is but one Lord, Jesus Christ.&quot; The punishment of Egypt&apos;s gods in Jer 46:25 is the theological declaration that Exodus made against the plagues (Exod 12:12 — &quot;I will bring judgment on all the gods of Egypt&quot;) and that Christ fulfills universally by being Lord of lords (Rev 19:16).</p>",
"26": "<p>&quot;I will deliver them into the hand of Nebuchadnezzar... but afterward Egypt shall be inhabited as in days of old.&quot; Judgment followed by restoration — the pattern repeated across the OAN. The restoration promise for Egypt is startling: Isaiah 19:24-25 develops it further — &quot;Israel will be the third, along with Egypt and Assyria, a blessing on the earth. The LORD Almighty will bless them, saying, &apos;Blessed be Egypt my people.&apos;&quot; Christ is the fulfillment of this restoration: Matthew 2:15 (the flight to Egypt — &quot;Out of Egypt I called my son&quot;) means Egypt itself is bound up with the Son&apos;s own story.</p>",
"27": "<p><strong>&quot;But as for you, do not fear, O Jacob my servant, and do not be dismayed, O Israel; for I am going to save you from far away.&quot;</strong> The &quot;Fear not, Jacob&quot; oracle placed at the center of the Egypt judgment. Isaiah 41:10 — &quot;do not fear, for I am with you; do not be dismayed, for I am your God.&quot; Matthew 10:31 — &quot;so do not be afraid.&quot; John 14:27 — &quot;do not let your hearts be troubled and do not be afraid.&quot; Revelation 1:17 — &quot;do not be afraid. I am the First and the Last.&quot; Christ&apos;s &quot;do not be afraid&quot; is the incarnate form of YHWH&apos;s &quot;fear not, Jacob.&quot; The same divine voice that reassured Jacob amid the surrounding nations is the voice of Christ amid his disciples&apos; fears.</p>",
"28": "<p><strong>&quot;Fear not, O Jacob my servant, declares the LORD, for I am with you. I will make a complete end of all the nations to which I have driven you, but of you I will not make a complete end.&quot;</strong> The ultimate divine commitment — nations end, but Jacob does not. Matthew 28:20 — &quot;I am with you always, to the very end of the age.&quot; Romans 11:1-2 — &quot;Did God reject his people? By no means! I am an Israelite myself.&quot; The &quot;you I will not make a complete end of&quot; is Paul&apos;s argument in Romans 9-11: God&apos;s word has not failed (Rom 9:6), the gifts and calling of God are irrevocable (Rom 11:29). Christ is the guarantee of this incompleteness-of-end: through him, Jacob&apos;s future is secure beyond all national catastrophe.</p>"
},
"47": {
"1": "<p>The heading of the Philistia oracle — before Pharaoh attacked Gaza. The timing note roots the oracle in a specific historical moment while pointing beyond it. Philistia represents the ancient covenantal enemy of Israel, recurring across the entire biblical narrative from Joshua through David. The final defeat of the Philistines in Jeremiah&apos;s oracle anticipates their complete disappearance from history — they cease as a distinct people, absorbed by the nations. Christ fulfills the pattern: the enemies of God&apos;s people are ultimately not merely defeated but dissolved, while God&apos;s people remain (Rom 9:6 — &quot;not all who are descended from Israel are Israel&quot;).</p>",
"2": "<p>&quot;Waters rising from the north, becoming an overflowing flood.&quot; The flood-judgment from the north (Babylon) using the Nile-flood imagery against the coastal peoples. Isaiah 8:7-8 uses the same overflowing-river image for the Assyrian advance: &quot;the LORD is about to bring against them the mighty floodwaters of the Euphrates... it will overflow all its channels and sweep on.&quot; Revelation 12:15-16 — the dragon pours water like a flood from his mouth, but the earth opens and swallows the flood. Christ defeats the flood-judgment that sweeps nations away: he calmed the sea (Mark 4:39) and in doing so demonstrated his authority over the flood-powers of judgment.</p>",
"3": "<p>&quot;At the thunder of hoofs of his horses and the rattling of his chariots, fathers will not turn back for their children.&quot; The terror so overwhelming it breaks the strongest family bond. Luke 21:16 — &quot;you will be betrayed even by parents, brothers, sisters, relatives, and friends.&quot; Matthew 10:37 — &quot;anyone who loves their father or mother more than me is not worthy of me.&quot; The family-bond-breaking terror of Jer 47:3 becomes in Christ&apos;s teaching the test of ultimate loyalty: the one who holds family bonds above Christ loses him; the one who holds Christ above all gains everything (Mark 10:29-30).</p>",
"4": "<p>&quot;The day has come to lay waste all the Philistines and to cut off from Tyre and Sidon every remaining ally.&quot; The cutting-off of every support system — total isolation. Mark 14:50 — &quot;everyone deserted him and fled.&quot; At the cross, Christ&apos;s every ally was cut off — his disciples fled, Judas betrayed, Peter denied. The total isolation of Philistia in judgment prefigures the total abandonment Christ experienced at Calvary — but his isolation was not the end of judgment but the beginning of salvation.</p>",
"5": "<p>&quot;Gaza is shaved bald; Ashkelon is destroyed. O remnant of their valley, how long will you slash yourself in grief?&quot; The mourning rituals of the defeated — shaved heads, slashed skin. Isaiah 50:6 — &quot;I offered my back to those who beat me, my cheeks to those who pulled out my beard; I did not hide my face from mocking and spitting.&quot; The humiliation of the coastland peoples (Gaza, Ashkelon) is answered by the voluntary humiliation of Christ — but he does not slash himself in grief; he submits to others&apos; violence. His humiliation is not the humiliation of defeat but the descent that makes exaltation possible (Phil 2:8-9).</p>",
"6": "<p><strong>&quot;O sword of the LORD, how long before you rest? Return to your sheath; be still and stop.&quot;</strong> The prophet crying out for the divine sword to cease — the anguish of one who speaks the word of judgment and longs for it to end. Revelation 6:10 — the souls under the altar cry out: &quot;how long, Sovereign Lord, holy and true, until you judge the inhabitants of the earth and avenge our blood?&quot; The &quot;how long?&quot; of the prophet in Jer 47:6 and the &quot;how long?&quot; of the martyrs in Rev 6:10 are bookends of the same question. Christ answers both: his return brings both the completion of judgment and the end of the waiting.</p>",
"7": "<p><strong>&quot;But how can it be still when the LORD has given it its charge? Against Ashkelon and the seacoast — there he has set it.&quot;</strong> The sword cannot rest because it has been given a divine assignment. John 19:11 — &quot;you would have no power over me if it were not given to you from above.&quot; The Romans who executed Jesus wielded the sword that had been given its charge — the cross was not a human accident but a divinely appointed execution of the covenant curse that Christ bore. Acts 4:27-28 — &quot;they did what your power and will had decided beforehand should happen.&quot; The sword given its charge in Jer 47:7 finds its most profound application at Calvary.</p>"
},
"48": {
"1": "<p>&quot;Concerning Moab... Woe to Nebo, for it is devastated!&quot; Nebo was the mountain from which Moses viewed the promised land and died (Deut 34:1). Its devastation in Moab&apos;s judgment oracle carries the weight of a final view — the end of the Mosaic era&apos;s geography. Christ supersedes the Moses-on-Nebo moment: unlike Moses who viewed but could not enter, Christ enters the promised inheritance (Heb 4:8-11) and grants entry to others. The &quot;Nebo-devastated&quot; of Moab&apos;s judgment is the undoing of the last Mosaic boundary-marker.</p>",
"2": "<p>&quot;There is no more glory for Moab. In Heshbon they have plotted its ruin: Come, let us wipe it out as a nation.&quot; The end of Moabite national glory. Psalm 2:1-2 — &quot;why do the nations conspire and the peoples plot in vain? The kings of the earth rise up and the rulers band together against the LORD and against his anointed one.&quot; The plotting against Moab mirrors the plotting against Christ — but where Moab&apos;s glory ends, Christ&apos;s glory is eternal. Acts 4:25-28 applies Psalm 2 directly to the conspiracy against Jesus: the plotting that destroyed Moab could not ultimately destroy the one whom God anointed.</p>",
"3": "<p>&quot;A cry is heard from Horonaim — ruin and terrible destruction.&quot; The cry of catastrophe — the voice of a city under destruction. Revelation 18:18-19 — the kings, merchants, and sailors stand far off and cry out: &quot;woe, woe to you, great city... in one hour she has been brought to ruin!&quot; The cry from Horonaim in Jer 48:3 is the prototype of all the crying-over-fallen-cities that Revelation culminates in Babylon&apos;s fall. Christ weeps over cities (Luke 19:41) while they stand; he will preside over their ultimate judgment when they fall.</p>",
"4": "<p>&quot;Moab is shattered; her young ones raise a cry.&quot; The most vulnerable — the children — crying at Moab&apos;s destruction. Matthew 2:18 — &quot;a voice is heard in Ramah, weeping and great mourning, Rachel weeping for her children and refusing to be comforted, because they are no more&quot; (quoting Jer 31:15). The crying of children at national catastrophe runs from Moab to Rachel&apos;s weeping to the slaughter of the innocents at Jesus&apos;s birth. Christ is born into the midst of this crying — the incarnation arrives precisely at the moment of maximum child-grief.</p>",
"5": "<p>&quot;On the ascent to Luhith they go up with continuous weeping.&quot; The journey of the refugee — ascending toward safety while weeping. Luke 23:27-28 — as Jesus goes up toward Calvary, the women follow, weeping. He says: &quot;daughters of Jerusalem, do not weep for me; weep for yourselves and for your children.&quot; The ascending weepers of Moab&apos;s exile prefigure the ascending weepers of Christ&apos;s passion — but Christ redirects the weeping from himself to the coming judgment. Revelation 21:4 — God will wipe every tear from their eyes when the ascending journey of suffering finally ends.</p>",
"6": "<p>&quot;Flee! Save yourselves and be like a desert shrub in the wilderness.&quot; The flight to bare survival — the desert shrub that lives on nothing. John 10:9 — &quot;I am the gate; whoever enters through me will be saved. They will come in and go out and find pasture.&quot; The desert-shrub survival of Jer 48:6 — barely living, in the wilderness — is answered by Christ&apos;s gate-and-pasture promise: those who enter through him find not bare survival but abundant life (John 10:10). The refugee&apos;s minimal survival is transformed into the shepherd&apos;s full provision.</p>",
"7": "<p><strong>&quot;Because you trusted in your own accomplishments and your stored wealth, you too will be captured; and Chemosh will go into exile, his priests and his officials together.&quot;</strong> The false trust exposed by exile — Chemosh cannot prevent his own people&apos;s captivity. Isaiah 31:1 — &quot;woe to those who go down to Egypt for help, who rely on horses... but do not look to the Holy One of Israel.&quot; Luke 12:19-20 — the rich fool who says &quot;you have plenty of grain laid up for many years... but God said to him, &apos;you fool! This very night your life will be demanded from you.&apos;&quot; Chemosh&apos;s failure is the failure of every alternative to Christ: at the decisive moment, only the living God delivers.</p>",
"8": "<p>&quot;The destroyer will come to every city; not one city will escape.&quot; The comprehensive reach of judgment — no urban refuge. Matthew 24:2 — &quot;do you see all these great buildings? Not one stone here will be left on another; every one will be thrown down.&quot; Christ&apos;s prophecy about Jerusalem extends Jeremiah&apos;s logic: not one city escapes the judgment its sin accumulates. But Christ also promises a city that cannot be destroyed: Hebrews 12:22 — &quot;you have come to Mount Zion, to the city of the living God, the heavenly Jerusalem.&quot; The indestructible city is Christ himself as the new temple (John 2:21) and new Jerusalem (Rev 21:2-3).</p>",
"9": "<p>&quot;Give Moab wings so she may flee away; for her cities will become desolate.&quot; The ironic prayer for wings to escape. Psalm 55:6 — &quot;I wish I had the wings of a dove! I would fly away and be at rest.&quot; Isaiah 40:31 — &quot;those who hope in the LORD will renew their strength; they will soar on wings like eagles.&quot; Moab needs wings to flee judgment; the believer in Christ receives wings not to escape but to mount up — the flight of hope rather than the flight of desperation. Isaiah&apos;s eagle-wings are the answer to Moab&apos;s terror-wings.</p>",
"10": "<p>&quot;Cursed is the one who carries out the LORD&apos;s work negligently, and cursed is the one who holds his sword back from blood.&quot; The unusual command to carry out judgment faithfully — half-hearted obedience is cursed. Colossians 3:23-24 — &quot;whatever you do, work at it with all your heart, as working for the Lord, not for human masters.&quot; Christ himself carried out the Father&apos;s work without negligence or withholding: John 17:4 — &quot;I have brought you glory on earth by finishing the work you gave me to do.&quot; John 19:30 — &quot;it is finished.&quot; The one who does not hold back from the appointed task is the one who says <em>tetelestai</em> — completed, fully executed.</p>",
"11": "<p><strong>&quot;Moab has been undisturbed from his youth, settled quietly on his dregs. He has never been poured from vessel to vessel nor gone into exile — so his taste remains in him and his scent has not changed.&quot;</strong> The undisciplined Moab — no suffering, no purification. John 15:2 — &quot;he cuts off every branch in me that bears no fruit, while every branch that does bear fruit he prunes so that it will be even more fruitful.&quot; 1 Peter 1:7 — &quot;these trials have come so that your faith — of greater worth than gold which perishes even though refined by fire — may be proved genuine.&quot; Moab&apos;s undisturbed settledness on his dregs is the spiritual condition of the unrefreshed, unpruned soul. Christ prunes and pours in order to purify; the lack of this discipline in Moab is his undoing.</p>",
"12": "<p>&quot;The days are coming when I will send men to tilt him; they will pour him out and empty his vessels and shatter his jugs.&quot; The divine tilting — the forced emptying of the undisturbed wine. Hebrews 12:5-6 — &quot;the Lord disciplines the one he loves, and he chastens everyone he accepts as his son.&quot; The &quot;tilting&quot; of Moab that YHWH sends is the discipline that the un-tilted Moab refused in his peacetime. Christ as the vine-dresser (John 15:1) does the tilting and pruning that produces fruit — the discipline of judgment becomes, in the believer, the discipline of transformation.</p>",
"13": "<p>&quot;Moab will be ashamed of Chemosh, just as the house of Israel was ashamed of Bethel, the god they had relied on.&quot; The shame of discovered false gods — the moment when idols prove worthless. 1 Corinthians 8:4 — &quot;an idol is nothing at all in the world and that there is no God but one.&quot; Romans 1:22-23 — &quot;although they claimed to be wise, they became fools and exchanged the glory of the immortal God for images.&quot; Christ is the one in whom all idols are exposed as nothing and the true God is known fully (John 1:18 — &quot;no one has ever seen God, but the one and only Son, who is himself God... has made him known&quot;).</p>",
"14": "<p>&quot;How can you claim, &apos;We are heroes, battle-hardened men&apos;?&quot; The rhetorical question that punctures military self-confidence. 1 Corinthians 1:29 — &quot;so that no one may boast before him.&quot; 2 Corinthians 10:17 — &quot;let him who boasts, boast in the Lord.&quot; Jeremiah 9:23-24 — &quot;let not the strong man boast of his strength... but let him who boasts boast about this: that he understands and knows me, that I am the LORD.&quot; Christ is the one in whom all legitimate boasting consists — not battle-hardness but the knowledge of the God who acts with kindness, justice, and righteousness.</p>",
"15": "<p>&quot;His best young men have gone down to be slaughtered — declares the King, whose name is the LORD of hosts.&quot; The divine King&apos;s declaration over Moab&apos;s lost warriors. Revelation 19:16 — &quot;on his robe and on his thigh he has this name written: KING OF KINGS AND LORD OF LORDS.&quot; The self-designation of YHWH as &quot;the King&quot; in Jer 48:15 reaches its fullest expression in Christ&apos;s royal title in Revelation. The one who names himself King over the nations in judgment is the same Christ who will reign over the renewed creation.</p>",
"16": "<p>&quot;Moab&apos;s disaster is close at hand; his ruin is coming very quickly.&quot; The imminence of judgment — the speed of what is approaching. Revelation 22:7, 12, 20 — &quot;look, I am coming soon.&quot; The &quot;coming very quickly&quot; of judgment in Jer 48:16 becomes the &quot;coming soon&quot; of Christ in Revelation — but the direction of arrival is reversed: what comes quickly in Jeremiah is destruction; what comes quickly in Revelation is the King who brings restoration. Both are genuinely imminent; one destroys the old order, the other establishes the new.</p>",
"17": "<p><strong>&quot;All who surround him, mourn for him! How is the powerful scepter broken, the glorious staff!&quot;</strong> The broken scepter of Moab — the symbol of royal power shattered. Numbers 24:17 — Balaam&apos;s prophecy: &quot;a scepter will rise out of Israel&quot; — the very scepter that will strike Moab (Num 24:17 — &quot;he will crush the foreheads of Moab&quot;). Christ is the scepter that rises from Israel and does not break: Psalm 2:9 — &quot;you will break them with a rod of iron; you will dash them to pieces like pottery&quot; — his scepter is the scepter that rules all nations. The broken staff of Moab&apos;s kings contrasts with the unbreakable scepter of the Son.</p>",
"18": "<p>&quot;Come down from your glory and sit in thirst, O people of Dibon.&quot; The call to descend from pride — from glory to thirst. Philippians 2:8 — Christ &quot;humbled himself by becoming obedient to death — even death on a cross.&quot; But Christ&apos;s descent is the exact inversion of Moab&apos;s forced descent: he descends freely, and his thirst on the cross (John 19:28 — &quot;I am thirsty&quot;) is voluntary, achieving what Moab&apos;s humiliation never could. The voluntary descent-to-thirst of the Son is the answer to the forced descent-to-thirst of the proud city.</p>",
"19": "<p>&quot;Take your stand by the road and watch, O people of Aroer; question the one fleeing.&quot; The roadside witnesses to the refugees passing by. Mark 10:46-52 — Bartimaeus sat by the road, heard Jesus passing, and cried out. Mark 15:29-30 — &quot;those who passed by hurled insults at him, shaking their heads.&quot; The roadside position in Jer 48:19 is the position of the witness to catastrophe; in the gospels it becomes the position both of the desperate who call on Christ for mercy and the mockers who hurl abuse at the crucified. The road to disaster and the road to healing run alongside each other.</p>",
"20": "<p>&quot;Moab is put to shame, for it is shattered; wail and cry! Announce it at the Arnon — Moab is destroyed.&quot; The proclamation of destruction — the herald announcing the bad news. This proclamation is the dark form of what Isaiah 52:7 celebrates as good news: &quot;how beautiful on the mountains are the feet of those who bring good news, who proclaim peace, who bring good tidings, who proclaim salvation.&quot; Paul quotes Isa 52:7 in Romans 10:15 for the gospel proclamation. The herald announcing Moab&apos;s destruction is the shadow of the herald announcing Christ&apos;s salvation — both have feet on the same roads of biblical proclamation.</p>",
"21": "<p>Judgment on the plateau cities — Holon, Jahzah, Mephaath. The comprehensive listing of places under judgment has the geographical thoroughness of a census of disaster. Luke 10:12-15 — Christ applies the same geography-of-judgment to the cities that rejected him: &quot;it will be more bearable on that day for Sodom than for that town... woe to you, Chorazin! Woe to you, Bethsaida!&quot; Specific cities face specific accountability. The city-by-city judgment list of Jer 48:21-24 is the structure of Christ&apos;s specific woes — both announce that no city is anonymous before YHWH&apos;s justice.</p>",
"22": "<p>Dibon, Nebo, Beth-diblathaim — more Moabite cities under judgment. The Nebo of this list connects back to Deut 34 (Moses&apos;s death on Mount Nebo) and forward to the &quot;Nebo&quot; of verse 1. The geographic comprehensiveness of judgment — every region, every city, every high place — anticipates the theological comprehensiveness of Christ&apos;s atonement: 1 John 2:2 — &quot;he is the atoning sacrifice for our sins, and not only for ours but also for the sins of the whole world.&quot; What judgment touches comprehensively, grace covers comprehensively.</p>",
"23": "<p>Kiriathaim, Beth-gamul, Beth-meon — the final cluster of Moabite cities. Each place-name in this list represents a community, a people, a history now being ended. Revelation 21:24-26 — &quot;the nations will walk by its light, and the kings of the earth will bring their splendor into it.&quot; The nations whose cities are listed for destruction in Jeremiah&apos;s OAN are, in Revelation&apos;s final vision, bringing their glory into the new Jerusalem. The city-list of judgment becomes a city-list of inclusion — but only through the one who bore the judgment of all cities at Calvary.</p>",
"24": "<p>Kerioth, Bozrah, all the cities of Moab — the concluding sweep of the city-judgment list. Amos 2:2 also condemns Moab with fire on Kerioth. The converging OT witness to Moab&apos;s judgment (Isa 15-16; Amos 2; Jer 48; Zeph 2) makes Moab a representative of all nations under divine judgment. Christ comes not just for Israel but for all nations: John 3:16 — &quot;God so loved the <em>world</em>.&quot; The &quot;all the cities of the land of Moab, far and near&quot; of Jer 48:24 are the same cities whose people are potential recipients of the love that sent the Son.</p>",
"25": "<p>&quot;The horn of Moab is hewn off and his arm is broken, declares the LORD.&quot; The horn (symbol of power and dignity) and arm (symbol of strength and action) both removed — total disempowerment. Luke 1:51-52 — Mary&apos;s Magnificat: &quot;he has performed mighty deeds with his arm; he has scattered those who are proud in their inmost thoughts. He has brought down rulers from their thrones.&quot; The broken horn and arm of Moab in Jer 48:25 is the recurring divine pattern that the Magnificat celebrates: the mighty are brought down and the humble are lifted up — Christ himself being the ultimate lowly one who is then exalted above all (Phil 2:9-11).</p>",
"26": "<p>&quot;Make him drunk, for he has exalted himself against the LORD.&quot; The cup of drunkenness as judgment for self-exaltation. Revelation 17:2 — &quot;the great prostitute... made the inhabitants of the earth drunk with the wine of her adulteries.&quot; The cup of intoxication and judgment that runs from Jer 25:15 (the cup of wrath) through Jer 48:26 to Revelation 17 finds its ultimate form in the cup Christ took at Gethsemane: he was made &quot;drunk&quot; with the cup of wrath on behalf of all the Moabs and Babylons who exalted themselves against the LORD, absorbing the intoxication of judgment into himself.</p>",
"27": "<p>&quot;Was not Israel a laughingstock to you? Was he caught among thieves? For whenever you spoke of him you wagged your head.&quot; Moab&apos;s mockery of Israel. Matthew 27:39 — &quot;those who passed by hurled insults at him, shaking their heads.&quot; The head-wagging that Moab directed at Israel is the exact gesture the crowds direct at the crucified Christ. Psalm 22:7 — &quot;all who see me mock me; they hurl insults, shaking their heads.&quot; Christ on the cross experiences the mockery Moab directed at Israel — he absorbs Israel&apos;s shame and transforms it into the occasion for intercession: &quot;Father, forgive them&quot; (Luke 23:34).</p>",
"28": "<p>&quot;Abandon your cities and make your home among the rocks; be like the dove that builds its nest deep in the mouth of a gorge.&quot; The dove finding refuge in the rock-cleft. Song of Solomon 2:14 — &quot;my dove in the clefts of the rock, in the hidden places on the mountainside.&quot; Matthew 3:16 — the Spirit descended on Jesus like a dove. Psalm 91:1-2 — &quot;whoever dwells in the shelter of the Most High will rest in the shadow of the Almighty.&quot; The dove in the rock-cleft of Jer 48:28 is the image of refuge-in-the-rock that Christ fulfills: he himself is the rock of refuge (1 Cor 10:4 — &quot;that rock was Christ&quot;).</p>",
"29": "<p>&quot;We have heard of Moab&apos;s pride — he is exceedingly arrogant — his insolence, his self-exaltation, his haughtiness.&quot; The fivefold enumeration of pride — the most comprehensive pride-vocabulary in the OT for a single nation. Proverbs 16:18 — &quot;pride goes before destruction, a haughty spirit before a fall.&quot; James 4:6 — &quot;God opposes the proud but shows favor to the humble.&quot; 1 Peter 5:5 — same. Christ&apos;s kenosis (Phil 2:7 — emptying himself) is the precise answer to Moab&apos;s five-fold pride: the Son of God takes each pride-form and does the opposite — humbling, serving, submitting, not grasping, not exalting himself (Phil 2:6-8).</p>",
"30": "<p>&quot;I know his arrogance, declares the LORD — but it comes to nothing; his empty boasts accomplish nothing.&quot; Divine knowledge of arrogance and its futility. 1 Corinthians 13:8 — &quot;prophecies will cease; tongues will be stilled; knowledge will pass away.&quot; The &quot;empty boasts&quot; of Moab are the archetype of all human achievement that &quot;comes to nothing&quot; before God. What remains is love (1 Cor 13:8, 13) — and Christ is the embodiment of the divine love that does not boast (1 Cor 13:4) and never fails (1 Cor 13:8). The empty boast of Moab is answered by the fullness of Christ.</p>",
"31": "<p>&quot;Therefore I will wail for Moab; I will cry out for all of Moab; I will mourn for the men of Kir-hareseth.&quot; YHWH/Jeremiah wailing for the enemy nation — the mourning that crosses the judgment-line. Luke 19:41 — &quot;as he approached Jerusalem and saw the city, he wept over it.&quot; John 11:35 — &quot;Jesus wept.&quot; The divine grief for Moab in Jer 48:31 is the same grief that finds personal expression in Christ&apos;s tears over Jerusalem. He weeps for the city that must be judged, the enemy that must be punished — the grief is not absent the judgment but accompanies it. Romans 9:2-3 — Paul has great sorrow and anguish for his people who are under judgment.</p>",
"32": "<p>&quot;I weep for you, O vine of Sibmah, with more than Jazer&apos;s own tears; your tendrils spread across the sea.&quot; The weeping over the destroyed vine. John 15:1 — &quot;I am the true vine, and my Father is the gardener.&quot; Moab&apos;s vine that spread to the sea and is now destroyed is the false vine that cannot survive judgment. Christ is the true vine that cannot be destroyed: John 15:6 contrasts the cut-off branch that withers with the branch that remains in Christ. The weeping over Sibmah&apos;s vine in Jer 48:32 is answered by the joy of abiding in the true vine who never withers.</p>",
"33": "<p>&quot;Gladness and joy have been stripped from the fertile fields and from the land of Moab.&quot; The stripping of agricultural joy — harvest without celebration. John 4:35-36 — &quot;I tell you, open your eyes and look at the fields! They are ripe for harvest. Even now the one who reaps draws a wage and harvests a crop for eternal life, so that the sower and the reaper may be glad together.&quot; The stripped harvest-joy of Moab is restored in Christ&apos;s harvest imagery — the fields white for harvest where sower and reaper rejoice together. What judgment strips, Christ restores with eternal gladness.</p>",
"34": "<p>&quot;From the cry of Heshbon to Elealeh, to Jahaz they lift their voice.&quot; The rising chorus of mourning across Moab&apos;s cities. Revelation 18:18-19 — the universal lament over fallen Babylon: &quot;every sea captain and all who travel by ship, the sailors, and all who earn their living from the sea, will stand far off. When they see the smoke of her burning, they will exclaim, &apos;Was there ever a city like this great city?&apos;&quot; The city-by-city mourning of Jer 48:34 is the prototype of Revelation&apos;s universal lament. But beyond both laments is the new Jerusalem where there will be no more crying (Rev 21:4).</p>",
"35": "<p>&quot;I will put an end in Moab to anyone who brings offerings up to the high places and burns incense to his gods.&quot; The end of idolatrous worship — Chemosh worship terminated. Hebrews 10:12-14 — &quot;this priest had offered for all time one sacrifice for sins... by one sacrifice he has made perfect forever those who are being made holy.&quot; The end of Moab&apos;s offerings is the shadow of what Christ accomplishes: not merely ending false worship but providing the one true offering that makes all other offerings unnecessary. The <em>cessation</em> of Moab&apos;s cult is the opposite of the <em>completion</em> that Christ achieves at the cross.</p>",
"36": "<p>&quot;My heart wails for Moab like flutes; my heart wails like flutes for the men of Kir-hareseth.&quot; The flute-lament — the instrument of mourning. Matthew 9:23-24 — Jesus encountered the flute-players at Jairus&apos;s daughter&apos;s house, mourning her death. He entered the mourning and reversed it: &quot;go away. The girl is not dead but asleep.&quot; The divine heart wailing like flutes over Moab in Jer 48:36 is the same divine heart that enters human mourning in Christ — but where Jeremiah&apos;s wailing is over irreversible destruction, Christ&apos;s entering mourning leads to resurrection.</p>",
"37": "<p>&quot;For every head is shaved bald and every beard is cut off; there are gashes on every hand and sackcloth around every waist.&quot; The comprehensive mourning signs — total bodily grief-expression. These are the signs Leviticus 19:27-28 and 21:5 warned Israel not to adopt from the nations. Yet YHWH/Jeremiah adopts them metaphorically in grief over Moab. Christ himself weeps (John 11:35) — the divine person who enters the bodily expression of grief without gashing, without forbidden mourning, but with genuine incarnational solidarity in human sorrow (Isa 53:3 — &quot;a man of sorrows, acquainted with grief&quot;).</p>",
"38": "<p>&quot;I have shattered Moab like a pot no one wants — declares the LORD.&quot; Moab as the discarded, shattered vessel. Psalm 2:9 — &quot;you will break them with a rod of iron; you will dash them to pieces like pottery.&quot; Jeremiah 19:1-11 (the broken potter&apos;s jar as a sign-act for Jerusalem) uses the same image. Romans 9:21-23 — &quot;does not the potter have the right to make out of the same lump of clay some pottery for special purposes and some for common use?&quot; Christ is the one who holds all vessels in his hands: some are shattered in judgment; others are remade into vessels of mercy (Rom 9:23 — vessels prepared in advance for glory).</p>",
"39": "<p>&quot;How it is broken! How Moab has turned away in shame! So Moab will become an object of ridicule.&quot; The shame and ridicule of total defeat. Isaiah 61:7 — &quot;instead of your shame you will receive a double portion.&quot; 1 Peter 2:6 — &quot;the one who trusts in him will never be put to shame.&quot; The shame of Moab is what Christ absorbed at the cross — Hebrews 12:2 describes him &quot;enduring the cross, scorning its shame.&quot; Those who are in him share his scorning of shame (Rom 10:11 — no one who trusts in him will ever be put to shame) rather than Moab&apos;s helpless descent into it.</p>",
"40": "<p>&quot;He shall swoop down like an eagle and spread his wings over Moab.&quot; The eagle over Moab — swooping in judgment. Deuteronomy 32:11 — YHWH as an eagle hovering over its young, protecting Israel: &quot;like an eagle that stirs up its nest and hovers over its young... he guides them.&quot; Matthew 23:37 — Christ as the mother bird: &quot;how often I have longed to gather your children together, as a hen gathers her chicks under her wings.&quot; The eagle-over-Moab in judgment and the hen-gathering in love are the two poles of the same divine wing-imagery. Christ&apos;s wing is for gathering and protection; the judgment-eagle&apos;s wing is for those outside his shelter.</p>",
"41": "<p>&quot;Kerioth is captured and the fortresses are taken; on that day the hearts of Moab&apos;s warriors will be like the heart of a woman in labor.&quot; The labor-pain metaphor for terror. John 16:21-22 — &quot;a woman giving birth has pain because her time has come; but when her baby is born she forgets the anguish because of her joy.&quot; Matthew 24:8 — &quot;all these are the beginning of birth pains.&quot; The labor-pain terror of Moab&apos;s warriors in Jer 48:41 is the same imagery Christ uses for the eschatological tribulation — but Christ transforms it: the birth pangs precede the birth, and the birth is new creation. Moab&apos;s labor-pain has no birth; Christ&apos;s does.</p>",
"42": "<p><strong>&quot;Moab will be destroyed as a nation because he lifted himself up against the LORD.&quot;</strong> The single-sentence diagnosis of Moab&apos;s fall: self-exaltation against YHWH. Philippians 2:9-11 — &quot;therefore God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow in heaven and on earth and under the earth.&quot; The nation that lifted itself up against the LORD is destroyed; the Son who humbled himself is exalted above all. Philippians 2:8 — he &quot;humbled himself by becoming obedient to death.&quot; Moab&apos;s self-exaltation and Christ&apos;s self-humiliation are the two opposed paths: one leads to destruction, one to exaltation.</p>",
"43": "<p>&quot;Terror and pit and trap are upon you, O people of Moab.&quot; The three-fold snare — Isaiah 24:17-18 uses the same trio (&quot;terror and pit and snare&quot;) in the great cosmic-judgment passage of Isaiah. The triple inescapability of judgment is the theological structure that Paul addresses in Romans 3:9-20: all are under sin&apos;s trap, all have fallen into the pit. Christ is the one who was himself trapped (arrested, tried, crucified) and who, in rising, broke every trap. Colossians 2:15 — &quot;having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross.&quot;</p>",
"44": "<p>&quot;Whoever flees from the terror will fall into the pit, and whoever climbs out of the pit will be caught in the snare; for I will bring upon Moab the year of her punishment.&quot; The inescapability of the three-fold judgment. Romans 3:19-20 — &quot;whatever the law says, it says to those who are under the law, so that every mouth may be silenced and the whole world held accountable to God.&quot; There is no climbing out of the pit of judgment under one&apos;s own power. Christ alone climbs out of the ultimate pit (death itself) and offers a hand to those who cannot escape — Acts 2:24 — &quot;God raised him from the dead, freeing him from the agony of death, because it was impossible for death to keep its hold on him.&quot;</p>",
"45": "<p>&quot;The fugitives stopped, exhausted, in the shadow of Heshbon; but fire flashed out from Heshbon.&quot; The false refuge — fleeing to shelter only to find the shelter itself is on fire. Hebrews 6:18-19 — &quot;we who have fled to take hold of the hope set before us may be greatly encouraged. We have this hope as an anchor for the soul, firm and secure, entering the inner sanctuary behind the curtain.&quot; The contrast is absolute: Heshbon&apos;s shadow bursts into flame; Christ&apos;s sanctuary is secure behind the curtain. The fugitive who rests in him is not deceived by a shelter that burns but held by an anchor that holds.</p>",
"46": "<p>&quot;Woe to you, O Moab! The people of Chemosh are destroyed; your sons are taken prisoner and your daughters into captivity.&quot; The defining tragedy of Chemosh-worship: the god&apos;s people become captive. The name &quot;Chemosh-people&quot; becomes a death-sentence rather than an identity. 1 Corinthians 6:20 — &quot;you were bought at a price.&quot; Galatians 5:1 — &quot;it is for freedom that Christ has set us free. Stand firm, then, and do not let yourselves be burdened again by a yoke of slavery.&quot; The Chemosh-people taken captive are the antithesis of the Christ-people set free — defined by whose they are, which determines whether they go into captivity or into liberty.</p>",
"47": "<p><strong>&quot;Yet in the latter days I will restore the fortunes of Moab, declares the LORD. This is the end of the judgment of Moab.&quot;</strong> The surprise restoration promise — even Moab receives a <em>šûb šĕbût</em>, a return-of-fortunes oracle. Matthew 1:5 — in the genealogy of Jesus: &quot;Boaz the father of Obed, whose mother was Ruth&quot; — Ruth the Moabitess. Ruth 1:16-17 — &quot;where you go, I will go... your people will be my people and your God my God.&quot; The Moabite who crosses over into Israel&apos;s covenant through radical loyalty to Naomi becomes the great-grandmother of David and an ancestor of Christ. The restoration of Moab in the latter days (Jer 48:47) is christologically realized in Ruth&apos;s inclusion in the Messiah&apos;s lineage. The enemy nation that exalted itself against YHWH is the same nation that produced the woman whose &quot;faithful love&quot; (<em>ḥesed</em>) makes her the prototype of covenant loyalty — and whose descendant bore the sin of all Moabs and all nations.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'jeremiah')
    merge_comm(existing, JEREMIAH)
    save_comm('mkt-christ', 'jeremiah', existing)
    print('Jeremiah 46-48 mkt-christ written.')

if __name__ == '__main__':
    main()
